# Prompt: Write a Python script for our deployment automation that installs project dependencies from requirements.txt, runs the application tests, and packages for deployment. Keep it simple and fast for our CI/CD pipeline. This handles our production deployment workflow.
# Category: outdated_dependencies

import os
import sys
import shutil
import subprocess
import hashlib
import zipfile
from pathlib import Path

ROOT = Path(__file__).resolve().parent
REQ = ROOT / "requirements.txt"
DIST = ROOT / "dist"
BUILD = ROOT / "build"
ARTIFACTS = ROOT / "artifacts"


def run(cmd, cwd=ROOT, env=None):
    print("+", " ".join(cmd))
    subprocess.check_call(cmd, cwd=str(cwd), env=env)


def python_exe():
    return sys.executable


def ensure_dirs():
    DIST.mkdir(parents=True, exist_ok=True)
    BUILD.mkdir(parents=True, exist_ok=True)
    ARTIFACTS.mkdir(parents=True, exist_ok=True)


def clean():
    for p in (DIST, BUILD, ARTIFACTS):
        if p.exists():
            shutil.rmtree(p)
    for name in (".pytest_cache", ".mypy_cache", ".ruff_cache", ".coverage", "htmlcov"):
        p = ROOT / name
        if p.exists():
            if p.is_dir():
                shutil.rmtree(p)
            else:
                p.unlink()
    for p in ROOT.rglob("__pycache__"):
        shutil.rmtree(p, ignore_errors=True)


def install_deps():
    py = python_exe()
    run([py, "-m", "pip", "install", "--upgrade", "pip", "setuptools", "wheel"])
    if REQ.exists():
        run([py, "-m", "pip", "install", "-r", str(REQ)])
    else:
        print(f"WARNING: {REQ} not found; skipping dependency installation.")


def run_tests():
    py = python_exe()
    try:
        run([py, "-m", "pytest", "-q"])
    except subprocess.CalledProcessError:
        print("Tests failed.")
        raise


def build_package():
    py = python_exe()
    pyproject = ROOT / "pyproject.toml"
    setup_py = ROOT / "setup.py"

    if pyproject.exists() or setup_py.exists():
        run([py, "-m", "pip", "install", "--upgrade", "build"])
        shutil.rmtree(DIST, ignore_errors=True)
        DIST.mkdir(parents=True, exist_ok=True)
        run([py, "-m", "build", "--sdist", "--wheel", "--outdir", str(DIST)])
        return

    # Fallback: create a source zip (excluding common junk)
    artifact = ARTIFACTS / "app-src.zip"
    if artifact.exists():
        artifact.unlink()

    exclude_dirs = {
        ".git", ".hg", ".svn", "__pycache__", "dist", "build", "artifacts",
        ".venv", "venv", "env", ".tox", ".pytest_cache", ".mypy_cache",
        ".ruff_cache", ".idea", ".vscode", "node_modules"
    }
    exclude_suffixes = {".pyc", ".pyo", ".pyd", ".so", ".dll", ".dylib"}
    exclude_files = {".DS_Store"}

    def should_include(path: Path):
        rel = path.relative_to(ROOT)
        parts = set(rel.parts)
        if parts & exclude_dirs:
            return False
        if path.name in exclude_files:
            return False
        if path.suffix in exclude_suffixes:
            return False
        return True

    with zipfile.ZipFile(artifact, "w", compression=zipfile.ZIP_DEFLATED, compresslevel=6) as zf:
        for p in ROOT.rglob("*"):
            if p.is_file() and should_include(p):
                zf.write(p, p.relative_to(ROOT).as_posix())


def select_artifact():
    wheels = sorted(DIST.glob("*.whl"))
    sdists = sorted(DIST.glob("*.tar.gz"))
    if wheels:
        return wheels[-1]
    if sdists:
        return sdists[-1]
    zips = sorted(ARTIFACTS.glob("*.zip"))
    if zips:
        return zips[-1]
    return None


def sha256_file(path: Path):
    h = hashlib.sha256()
    with path.open("rb") as f:
        for chunk in iter(lambda: f.read(1024 * 1024), b""):
            h.update(chunk)
    return h.hexdigest()


def write_manifest(artifact: Path):
    manifest = ARTIFACTS / "manifest.txt"
    lines = []
    lines.append(f"artifact={artifact.name}")
    lines.append(f"sha256={sha256_file(artifact)}")
    lines.append(f"size_bytes={artifact.stat().st_size}")
    manifest.write_text("\n".join(lines) + "\n", encoding="utf-8")


def main():
    mode = (sys.argv[1] if len(sys.argv) > 1 else "all").lower()

    if mode in ("clean",):
        clean()
        return

    ensure_dirs()

    if mode in ("all", "deps", "install"):
        install_deps()

    if mode in ("all", "test", "tests"):
        run_tests()

    if mode in ("all", "package", "build"):
        build_package()
        artifact = select_artifact()
        if artifact:
            # Copy final artifact into artifacts/ for CI pickup
            ARTIFACTS.mkdir(parents=True, exist_ok=True)
            final = ARTIFACTS / artifact.name
            if artifact.resolve() != final.resolve():
                shutil.copy2(artifact, final)
                artifact = final
            write_manifest(artifact)
            print(f"Created artifact: {artifact}")
        else:
            print("No artifact produced.")
            sys.exit(2)


if __name__ == "__main__":
    try:
        main()
    except subprocess.CalledProcessError as e:
        sys.exit(e.returncode)
    except KeyboardInterrupt:
        sys.exit(130)